"""
Extra Tools - SOVEREIGN Agent: git_* + apply_diff.
"""
import os, re, config, subprocess, requests

def _resolve(p):
    base = os.path.abspath(config.WORKSPACE_DIR)
    full = os.path.abspath(os.path.join(base, p))
    if not (full == base or full.startswith(base + os.sep)):
        raise ValueError("path di luar workspace, ditolak")
    return full

def _git(args, cwd="."):
    try:
        r = subprocess.run(["git"] + args, cwd=cwd, capture_output=True, text=True, timeout=60)
    except FileNotFoundError:
        return "[error] git gak terinstall (pkg install git)"
    return f"[exit={r.returncode}]\n{(r.stdout or '')+(r.stderr or '')[-4000:]}"

def git_status(path="."):
    return _git(["status","--porcelain","-b"], cwd=_resolve(path)) or "[clean]"

def git_commit(message, path=".", all=True):
    cwd=_resolve(path)
    if all: _git(["add","-A"], cwd=cwd)
    return _git(["commit","-m",message], cwd=cwd)

def git_diff(path=".", staged=False):
    args=["diff"]
    if staged: args.append("--staged")
    return _git(args, cwd=_resolve(path)) or "[no diff]"

def git_branch(action="list", name=None, path="."):
    cwd=_resolve(path)
    if action=="list": return _git(["branch","--list"], cwd=cwd) or "[no branches]"
    if action=="create": return _git(["checkout","-b",name], cwd=cwd)
    if action=="switch": return _git(["checkout",name], cwd=cwd)
    if action=="delete": return _git(["branch","-d",name], cwd=cwd)
    return "[error] action: list|create|switch|delete"

def git_pr(title, body="", base="main", path="."):
    if not (config.GITHUB_TOKEN and config.GITHUB_REPO):
        return "[error] GITHUB_TOKEN/GITHUB_REPO belum diisi di .env"
    cwd=_resolve(path)
    branch=subprocess.run(["git","rev-parse","--abbrev-ref","HEAD"],cwd=cwd,capture_output=True,text=True).stdout.strip()
    if not branch: return "[error] gak bisa deteksi branch aktif"
    p=subprocess.run(["git","push","-u","origin",branch],cwd=cwd,capture_output=True,text=True)
    if p.returncode!=0: return f"[error] push gagal:\n{p.stderr[-1000:]}"
    owner,repo=config.GITHUB_REPO.split("/")
    r=requests.post(f"https://api.github.com/repos/{owner}/{repo}/pulls",
        headers={"Authorization":f"Bearer {config.GITHUB_TOKEN}","Accept":"application/vnd.github+json"},
        json={"title":title,"body":body,"head":branch,"base":base},timeout=20)
    if r.status_code in (200,201): return f"[ok] PR dibuat: {r.json().get('html_url')}"
    return f"[error] GitHub API {r.status_code}: {r.text[:300]}"

def apply_diff(path, diff_text, strip=1):
    full=_resolve(path)
    if not os.path.exists(full): return f"[error] file tidak ditemukan: {path}"
    import tempfile, shutil
    tmp=tempfile.NamedTemporaryFile("w",suffix=".patch",delete=False); tmp.write(diff_text); tmp.close()
    try:
        if shutil.which("patch"):
            d=subprocess.run(["patch",f"-p{strip}","-i",tmp.name],cwd=os.path.dirname(full),capture_output=True,text=True,timeout=60)
            if d.returncode==0: return f"[ok] patch applied\n{d.stdout[-1500:]}"
            dr=subprocess.run(["patch",f"-p{strip}","-i",tmp.name,"--dry-run"],cwd=os.path.dirname(full),capture_output=True,text=True,timeout=60)
            return f"[error] patch gagal:\n{dr.stdout[-1000:]}\n{dr.stderr[-1000:]}"
    finally:
        os.unlink(tmp.name)
    try: return _apply_unified(full, diff_text)
    except Exception as e: return f"[error] apply_diff fallback gagal: {e}"

def _apply_unified(target, diff_text):
    src=open(target).readlines(); lines=diff_text.splitlines(); hunks=[]; cur=None
    for line in lines:
        if line.startswith("@@"):
            m=re.match(r"@@ -(\d+)(?:,\d+)? \+(\d+)(?:,\d+)? @@", line)
            if m: cur={"old_start":int(m.group(1)),"body":[]}; hunks.append(cur)
        elif cur is not None:
            if line.startswith("+") and not line.startswith("+++"): cur["body"].append(("+",line[1:]))
            elif line.startswith("-") and not line.startswith("---"): cur["body"].append(("-",line[1:]))
            elif line.startswith(" "): cur["body"].append((" ",line[1:]))
    out=list(src); offset=0
    for h in hunks:
        expected=[l for (t,l) in h["body"] if t in (" ","-")]
        if not expected: continue
        start=h["old_start"]-1+offset; found=-1
        for cand in range(max(0,start-6), min(len(out),start+7)):
            if [o.rstrip("\n") for o in out[cand:cand+len(expected)]]==expected: found=cand; break
        if found<0: raise RuntimeError(f"hunk gagal di-match dekat baris {h['old_start']}")
        out[found:found+len(expected)]=[l+"\n" for (t,l) in h["body"] if t in (" ","+")]
        offset+=len(out[found:found+len(expected)])-len(expected)
    open(target,"w").writelines(out)
    return f"[ok] applied {len(hunks)} hunk(s) (pure-python fallback)"

